window.__PAGE_RUNTIME_PARTIALS__["partials/guia-05-herramientas-content.html"] = "\u003cbutton class=\"hamburger\" onclick=\"toggleSidebar()\" aria-label=\"Menú\"\u003e\u0026#9776;\u003c/button\u003e\r\n\u003cbutton class=\"btn-sb-expand\" onclick=\"showSidebar()\" title=\"Mostrar barra lateral\"\u003e\u0026#9776;\u003c/button\u003e\r\n\r\n\u003cdiv class=\"layout app-layout\"\u003e\r\n  \u003cnav class=\"sidebar\" id=\"sidebar\"\u003e\r\n    \u003cdiv class=\"sidebar-logo\"\u003e\r\n      \u003cdiv class=\"badge\"\u003eSENA · FPI\u003c/div\u003e\r\n      \u003ch2\u003eGuia 5 - Operar Herramientas Informaticas y Digitales\u003c/h2\u003e\r\n      \u003cp\u003eSistemas Teleinformaticos\u003c/p\u003e\r\n      \u003cbutton class=\"btn-sb-collapse\" onclick=\"hideSidebar()\" title=\"Ocultar barra lateral\"\u003e\u0026#9664;\u003c/button\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"sidebar-ficha\" id=\"sb-ficha-ok\" style=\"display:none\"\u003e\r\n      \u003cdiv class=\"sf-label\"\u003eTu grupo\u003c/div\u003e\r\n      \u003cdiv class=\"sf-inst\" id=\"sb-inst\"\u003e\u003c/div\u003e\r\n      \u003cdiv class=\"sf-meta\" id=\"sb-grupo-meta\"\u003e\u003c/div\u003e\r\n      \u003cdiv class=\"sf-badge\" id=\"sb-badge\"\u003e\u003c/div\u003e\r\n    \u003c/div\u003e\r\n    \u003cdiv class=\"sidebar-noficha\" id=\"sb-ficha-warn\"\u003e\r\n      \u003ca href=\"index.html\"\u003eInicio | Seleccionar grupo / ficha\u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"progress-wrap\"\u003e\r\n      \u003cdiv class=\"progress-label\"\u003e\r\n        \u003cspan\u003eProgreso\u003c/span\u003e\r\n        \u003cspan id=\"progressValue\"\u003e0%\u003c/span\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"progress-bar-bg\"\u003e\r\n        \u003cdiv class=\"progress-bar\" id=\"progressBar\"\u003e\u003c/div\u003e\r\n      \u003c/div\u003e\r\n      \u003cp class=\"progress-note\"\u003eEl avance se guarda localmente en este navegador.\u003c/p\u003e\r\n      \u003cbutton type=\"button\" class=\"reset-button\" id=\"resetProgress\"\u003eReiniciar respuestas\u003c/button\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eInformaci\u0026oacute;n\u003c/div\u003e\r\n      \u003ca class=\"nav-link active\" href=\"#identificacion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128203;\u003c/span\u003e Identificaci\u0026oacute;n\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#presentacion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128075;\u003c/span\u003e Presentaci\u0026oacute;n\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eActividades\u003c/div\u003e\r\n      \u003ca class=\"nav-link\" href=\"#reflexion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128172;\u003c/span\u003e 3.1 Reflexi\u0026oacute;n Inicial\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#contexto\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128269;\u003c/span\u003e 3.2 Contextualizaci\u0026oacute;n\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#apropiacion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128218;\u003c/span\u003e 3.3 Apropiaci\u0026oacute;n\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#transferencia\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128640;\u003c/span\u003e 3.4 Transferencia\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eRecursos\u003c/div\u003e\r\n      \u003ca class=\"nav-link\" href=\"#evidencias\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128202;\u003c/span\u003e Evidencias\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#glosario\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128214;\u003c/span\u003e Glosario\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#referencias\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128279;\u003c/span\u003e Referencias\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#material-apoyo\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128194;\u003c/span\u003e Material de Apoyo\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eGuia asignada\u003c/div\u003e\r\n      \u003ca class=\"nav-guide current\" id=\"currentGuideNavLink\" href=\"grupo-11a-guia-05-herramientas-informaticas-digitales.html\" data-current-file=\"grupo-11a-guia-05-herramientas-informaticas-digitales.html\"\u003e\r\n        \u003cspan class=\"g-icon\"\u003e\u0026#128215;\u003c/span\u003e\r\n        \u003cspan class=\"g-info\"\u003e\r\n          \u003cspan class=\"g-num\"\u003eGuia 5\u003c/span\u003e\r\n          \u003cspan class=\"g-name\" id=\"currentGuideNavLabel\"\u003eOperar herramientas informaticas y digitales | 11A\u003c/span\u003e\r\n        \u003c/span\u003e\r\n        \u003cspan class=\"g-tag actual\"\u003eActual\u003c/span\u003e\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003ca class=\"nav-home-link\" href=\"calendario-academico-2026.html\"\u003e\u0026#128197; \u003cspan\u003eCalendario 2026\u003c/span\u003e\u003c/a\u003e\r\n    \u003ca class=\"nav-home-link\" href=\"index.html\"\u003e\u0026#127968; \u003cspan\u003eVolver al Inicio\u003c/span\u003e\u003c/a\u003e\r\n  \u003c/nav\u003e\r\n\r\n  \u003cmain class=\"main app-main\"\u003e\r\n    \u003cdiv class=\"topbar\"\u003e\r\n      \u003cdiv class=\"topbar-title\"\u003e\r\n        \u003cstrong\u003eGuia 5 - Operar Herramientas Informaticas y Digitales\u003c/strong\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"topbar-meta\"\u003e\r\n        \u003cspan class=\"meta-item\"\u003e\u003cspan\u003e\u0026#9201;\u003c/span\u003e\u003cspan\u003e48 horas\u003c/span\u003e\u003c/span\u003e\r\n        \u003cspan class=\"meta-item\"\u003e\u003cspan\u003e\u0026#128197;\u003c/span\u003e\u003cspan\u003e2026\u003c/span\u003e\u003c/span\u003e\r\n        \u003cspan class=\"meta-item\"\u003e\u003cspan\u003e\u0026#127979;\u003c/span\u003e\u003cspan id=\"topbarCampus\"\u003eSanta Barbara | 11A\u003c/span\u003e\u003c/span\u003e\r\n      \u003c/div\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"content\"\u003e\r\n      \u003cdiv class=\"hero\" id=\"inicio\"\u003e\r\n        \u003cdiv class=\"tag\"\u003eGuia 5 | Fase: Evaluacion\u003c/div\u003e\r\n        \u003ch1\u003eOperar herramientas informaticas y digitales\u003c/h1\u003e\r\n        \u003cp\u003e\r\n          En esta guia reconocerás herramientas digitales, clasificarás archivos,\r\n          compararás sistemas operativos y documentarás procedimientos tecnicos\r\n          en entornos controlados.\r\n        \u003c/p\u003e\r\n        \u003cdiv class=\"hero-meta\"\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#127963; SENA \u0026mdash; Servicio Nacional de Aprendizaje\u003c/div\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#128205; Competencia: Operar herramientas informaticas y digitales\u003c/div\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#9201; 48 horas\u003c/div\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#127891; C\u0026oacute;digo: 233108 \u0026middot; V1\u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"identificacion\" class=\"section-title\"\u003eIdentificaci\u0026oacute;n de la Gu\u0026iacute;a\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#e8f5e9\"\u003e\u0026#128203;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eDatos del Programa de Formaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003eInformaci\u0026oacute;n oficial del programa y la competencia\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"table-scroll\"\u003e\r\n            \u003ctable class=\"data-table ident-table\"\u003e\r\n              \u003ctbody\u003e\r\n                \u003ctr\u003e\u003ctd\u003eDenominaci\u0026oacute;n del Programa\u003c/td\u003e\u003ctd\u003eSistemas Teleinform\u0026aacute;ticos\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eC\u0026oacute;digo del Programa\u003c/td\u003e\u003ctd\u003e233108 \u0026middot; Versi\u0026oacute;n 1\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eNombre del Proyecto Formativo\u003c/td\u003e\u003ctd\u003eFortalecimiento de los servicios Teleinform\u0026aacute;ticos de equipos y redes en las MIPYMES de la regi\u0026oacute;n.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eFase del Proyecto\u003c/td\u003e\u003ctd\u003eEvaluaci\u0026oacute;n\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eActividad del Proyecto\u003c/td\u003e\u003ctd\u003eDiagnosticar el estado de la infraestructura de redes, equipos inform\u0026aacute;ticos y solicitudes de servicio t\u0026eacute;cnico.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eCompetencia\u003c/td\u003e\u003ctd\u003eOperar herramientas inform\u0026aacute;ticas y digitales de acuerdo con protocolos y manuales t\u0026eacute;cnicos.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eResultado de Aprendizaje\u003c/td\u003e\u003ctd\u003eRAP 1 - Caracterizar herramientas inform\u0026aacute;ticas seg\u0026uacute;n el contexto tecnol\u0026oacute;gico de la organizaci\u0026oacute;n.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eDuraci\u0026oacute;n\u003c/td\u003e\u003ctd\u003e48 Horas\u003c/td\u003e\u003c/tr\u003e\r\n              \u003c/tbody\u003e\r\n            \u003c/table\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"presentacion\" class=\"section-title\"\u003ePresentaci\u0026oacute;n\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#e3f2fd\"\u003e\u0026#128075;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eBienvenida a la Gu\u0026iacute;a\u003c/h3\u003e\r\n              \u003cp\u003eConoce el contexto y las metas de esta gu\u0026iacute;a de herramientas digitales\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cp class=\"intro-text\"\u003e\r\n            Bienvenido, aprendiz, a la gu\u0026iacute;a \u003cstrong\u003eOperar herramientas inform\u0026aacute;ticas y digitales\u003c/strong\u003e.\r\n            En este recorrido fortalecer\u0026aacute;s el uso de recursos digitales para documentar procesos,\r\n            clasificar informaci\u0026oacute;n y resolver situaciones t\u0026eacute;cnicas con criterio.\r\n          \u003c/p\u003e\r\n          \u003cp class=\"intro-text\"\u003e\r\n            Esta gu\u0026iacute;a te acerca al reconocimiento de herramientas, extensiones de archivo,\r\n            sistemas operativos y procesos de instalaci\u0026oacute;n en entornos controlados, siempre\r\n            promoviendo el orden, la seguridad y la correcta documentaci\u0026oacute;n del trabajo realizado.\r\n          \u003c/p\u003e\r\n          \u003cp class=\"intro-text\"\u003e\r\n            Las actividades est\u0026aacute;n articuladas al programa \u003cstrong\u003eSistemas Teleinform\u0026aacute;ticos\u003c/strong\u003e\r\n            y al proyecto formativo orientado al fortalecimiento de servicios teleinform\u0026aacute;ticos\r\n            en equipos y redes para las MIPYMES de la regi\u0026oacute;n.\r\n          \u003c/p\u003e\r\n          \u003cdiv class=\"info-box green\" style=\"margin-top:14px\"\u003e\r\n            \u003cdiv class=\"label\"\u003eEn esta gu\u0026iacute;a desarrollar\u0026aacute; actividades que le permitir\u0026aacute;n:\u003c/div\u003e\r\n            \u003cul\u003e\r\n              \u003cli\u003eReconocer conceptos b\u0026aacute;sicos sobre restauraci\u0026oacute;n, arranque y formateo.\u003c/li\u003e\r\n              \u003cli\u003eRelacionar herramientas digitales con sus funciones y usos.\u003c/li\u003e\r\n              \u003cli\u003eClasificar extensiones de archivo y programas asociados.\u003c/li\u003e\r\n              \u003cli\u003eInvestigar requerimientos m\u0026iacute;nimos de sistemas operativos.\u003c/li\u003e\r\n              \u003cli\u003eDocumentar procesos de instalaci\u0026oacute;n y evidencias t\u0026eacute;cnicas de manera organizada.\u003c/li\u003e\r\n            \u003c/ul\u003e\r\n          \u003c/div\u003e\r\n          \u003cdiv class=\"quote\"\u003e\r\n            \"Aprender a usar bien las herramientas digitales tambi\u0026eacute;n es aprender a resolver problemas con orden, criterio y responsabilidad.\"\r\n            \u003ccite\u003eGu\u0026iacute;a 5 - Orientaci\u0026oacute;n de trabajo\u003c/cite\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"reflexion\" class=\"section-title\"\u003e3.1 \u0026middot; Actividades de Reflexi\u0026oacute;n Inicial\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eAntes de intervenir equipos o software, analice el caso, identifique s\u0026iacute;ntomas y organice un procedimiento seguro de diagn\u0026oacute;stico.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-reflexion\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128172;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Reflexi\u0026oacute;n Inicial\u003c/h3\u003e\r\n              \u003cp\u003e1 actividad \u0026middot; Duraci\u0026oacute;n aproximada: 1 hora\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.1.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eCaso de diagnostico: equipos sin arranque\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision de arranque\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e analizar un caso real de equipos sin arranque, identificar causas probables y proponer un plan de revisi\u0026oacute;n seguro. Producto: bit\u0026aacute;cora con 3 momentos (observaci\u0026oacute;n, an\u0026aacute;lisis, plan + cierre).\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g5-1\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eM\u0026eacute;todo de diagn\u0026oacute;stico de arranque\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g5-1\" data-ihelp-title=\"M\u0026eacute;todo de diagn\u0026oacute;stico de arranque\"\u003e\n                \u003cp\u003eAntes de tocar nada del equipo:\u003c/p\u003e\r\n                    \u003col\u003e\r\n                      \u003cli\u003eLea con atenci\u0026oacute;n el mensaje en pantalla y antelo tal cual aparece.\u003c/li\u003e\r\n                      \u003cli\u003eObserve si el equipo enciende: luces, ventilador, pitidos del POST.\u003c/li\u003e\r\n                      \u003cli\u003eEntre a la BIOS/UEFI (F2, F10, Del seg\u0026uacute;n marca) y revise el \u003cem\u003eorden de arranque\u003c/em\u003e: el disco debe estar listado.\u003c/li\u003e\r\n                      \u003cli\u003eSi no aparece el disco, apague y revise cables SATA/alimentaci\u0026oacute;n.\u003c/li\u003e\r\n                    \u003c/ol\u003e\r\n                    \u003cp\u003e\u003cstrong\u003eNUNCA\u003c/strong\u003e empiece formateando \"por si acaso\": eso borra datos del usuario sin saber a\u0026uacute;n cu\u0026aacute;l era el problema.\u003c/p\u003e\r\n                    \u003cdiv class=\"ihelp-panel__example\"\u003eCaso t\u0026iacute;pico: el disco est\u0026aacute; conectado pero la BIOS lo ten\u0026iacute;a fuera del orden de arranque. Soluci\u0026oacute;n: entrar a BIOS, mover el disco al primer lugar y guardar (F10).\n              \u003c/div\u003e\u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"diagnostic-layout\"\u003e\r\n                \u003carticle class=\"case-card case-hero\"\u003e\r\n                  \u003cdiv class=\"subsection-head\"\u003e\r\n                    \u003cspan class=\"case-label\"\u003eSituacion problema\u003c/span\u003e\r\n                    \u003cp\u003eAnaliza el escenario antes de empezar tu bitacora de diagnostico.\u003c/p\u003e\r\n                  \u003c/div\u003e\r\n                  \u003ch3\u003eRecepcion de equipos recien ensamblados\u003c/h3\u003e\r\n                  \u003cp\u003e\r\n                    Se recibio un grupo de quince computadores nuevos para ser ensamblados.\r\n                    Despues del ensamble, al encenderlos aparece una advertencia de arranque\r\n                    y se debe verificar que componente o configuracion falta para lograr\r\n                    la operatividad total.\r\n                  \u003c/p\u003e\r\n                  \u003cdiv class=\"info-box blue\"\u003e\r\n                    \u003cstrong\u003eMeta de la actividad\u003c/strong\u003e\r\n                    \u003cp\u003e\r\n                      Identificar causas probables, organizar una revision segura y\r\n                      seleccionar herramientas digitales para documentar el caso.\r\n                    \u003c/p\u003e\r\n                  \u003c/div\u003e\r\n                  \u003cdiv class=\"diagnosis-points\"\u003e\r\n                    \u003cdiv class=\"diagnosis-point\"\u003e\r\n                      \u003cstrong\u003eObserva\u003c/strong\u003e\r\n                      \u003cp\u003eReconoce que mensaje aparece y en que momento del arranque se presenta la falla.\u003c/p\u003e\r\n                    \u003c/div\u003e\r\n                    \u003cdiv class=\"diagnosis-point\"\u003e\r\n                      \u003cstrong\u003eAnaliza\u003c/strong\u003e\r\n                      \u003cp\u003eRelaciona sintomas, evidencias y causas posibles sin intervenir de forma apresurada.\u003c/p\u003e\r\n                    \u003c/div\u003e\r\n                    \u003cdiv class=\"diagnosis-point\"\u003e\r\n                      \u003cstrong\u003eDocumenta\u003c/strong\u003e\r\n                      \u003cp\u003eRegistra una ruta de revision clara y las herramientas digitales con las que entregarias el caso.\u003c/p\u003e\r\n                    \u003c/div\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/article\u003e\r\n\r\n                \u003caside class=\"support-column\"\u003e\r\n                  \u003cdiv class=\"support-card\"\u003e\r\n                    \u003cdiv class=\"subsection-head\"\u003e\r\n                      \u003cstrong\u003eEvidencias visuales del caso\u003c/strong\u003e\r\n                      \u003cp\u003eUsa estas pistas para orientar tu analisis tecnico.\u003c/p\u003e\r\n                    \u003c/div\u003e\r\n                    \u003cdiv class=\"diagnosis-gallery\"\u003e\r\n                      \u003cfigure class=\"media-card\"\u003e\r\n                        \u003cimg\r\n                          src=\"assets/img/no-bootable-device.jpeg\"\r\n                          alt=\"Mensaje de no bootable device\"\r\n                        \u003e\r\n                        \u003cfigcaption\u003eNo bootable device\u003c/figcaption\u003e\r\n                      \u003c/figure\u003e\r\n                      \u003cfigure class=\"media-card\"\u003e\r\n                        \u003cimg\r\n                          src=\"assets/img/operating-system-not-found.jpeg\"\r\n                          alt=\"Mensaje de operating system not found\"\r\n                        \u003e\r\n                        \u003cfigcaption\u003eOperating system not found\u003c/figcaption\u003e\r\n                      \u003c/figure\u003e\r\n                    \u003c/div\u003e\r\n                  \u003c/div\u003e\r\n\r\n                  \u003cdiv class=\"checklist-card compact-card\"\u003e\r\n                    \u003ch4\u003eSenales que puedes registrar\u003c/h4\u003e\r\n                    \u003cul class=\"mini-list\"\u003e\r\n                      \u003cli\u003eMensaje exacto mostrado por BIOS o UEFI.\u003c/li\u003e\r\n                      \u003cli\u003ePresencia o ausencia del disco en la configuracion de arranque.\u003c/li\u003e\r\n                      \u003cli\u003eCables, conexiones y respuesta general del equipo al encender.\u003c/li\u003e\r\n                      \u003cli\u003eAcciones que deben evitarse hasta confirmar la causa del fallo.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/aside\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"checklist-card compact-card\"\u003e\r\n                \u003cdiv class=\"subsection-head\"\u003e\r\n                  \u003cstrong\u003eRuta sugerida de diagnostico\u003c/strong\u003e\r\n                  \u003cp\u003eOrdena tu respuesta en cuatro momentos antes de diligenciar la bitacora.\u003c/p\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv class=\"diagnostic-steps\"\u003e\r\n                  \u003carticle class=\"step-card\"\u003e\r\n                    \u003cspan class=\"step-number\"\u003e1\u003c/span\u003e\r\n                    \u003cstrong\u003eLectura del caso\u003c/strong\u003e\r\n                    \u003cp\u003eComprende el contexto del ensamble y la falla reportada antes de proponer acciones.\u003c/p\u003e\r\n                  \u003c/article\u003e\r\n                  \u003carticle class=\"step-card\"\u003e\r\n                    \u003cspan class=\"step-number\"\u003e2\u003c/span\u003e\r\n                    \u003cstrong\u003eRegistro de sintomas\u003c/strong\u003e\r\n                    \u003cp\u003eDescribe lo que ocurre al encender, el mensaje observado y las evidencias visibles.\u003c/p\u003e\r\n                  \u003c/article\u003e\r\n                  \u003carticle class=\"step-card\"\u003e\r\n                    \u003cspan class=\"step-number\"\u003e3\u003c/span\u003e\r\n                    \u003cstrong\u003eAnalisis tecnico\u003c/strong\u003e\r\n                    \u003cp\u003ePropone causas probables y define que accion no realizarias de inmediato.\u003c/p\u003e\r\n                  \u003c/article\u003e\r\n                  \u003carticle class=\"step-card\"\u003e\r\n                    \u003cspan class=\"step-number\"\u003e4\u003c/span\u003e\r\n                    \u003cstrong\u003ePlan y entrega\u003c/strong\u003e\r\n                    \u003cp\u003eOrganiza la revision por pasos y selecciona herramientas para documentar el caso.\u003c/p\u003e\r\n                  \u003c/article\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"panel-grid\"\u003e\r\n                \u003cform class=\"work-form\" autocomplete=\"off\"\u003e\r\n                  \u003cdiv class=\"form-intro\"\u003e\r\n                    \u003cspan\u003eBitacora de trabajo\u003c/span\u003e\r\n                    \u003ch3\u003eRegistra tu diagnostico inicial\u003c/h3\u003e\r\n                    \u003cp\u003e\r\n                      Completa la actividad en tres momentos: observacion del caso,\r\n                      analisis del fallo y plan de revision segura.\r\n                    \u003c/p\u003e\r\n                  \u003c/div\u003e\r\n\r\n                  \u003cdiv class=\"bitacora-stack\"\u003e\r\n                    \u003csection class=\"bitacora-block\"\u003e\r\n                      \u003cdiv class=\"subsection-head\"\u003e\r\n                        \u003cstrong\u003e1. Observacion del caso\u003c/strong\u003e\r\n                        \u003cp\u003eDescribe sintomas, mensajes y evidencias tal como los identificas.\u003c/p\u003e\r\n                      \u003c/div\u003e\r\n                      \u003cdiv class=\"form-grid\"\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003eQue pasa al encender\u003c/span\u003e\r\n                          \u003ctextarea rows=\"4\" data-store=\"bitacora-sintomas\" data-track placeholder=\"Describe sintomas, comportamiento del equipo y momento en que ocurre la falla.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003eMensaje en pantalla\u003c/span\u003e\r\n                          \u003ctextarea rows=\"4\" data-store=\"bitacora-mensaje\" data-track placeholder=\"Transcribe o resume el mensaje observado.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003eEvidencias observadas\u003c/span\u003e\r\n                          \u003ctextarea rows=\"4\" data-store=\"bitacora-evidencias\" data-track placeholder=\"Luces, pitidos, ventiladores, pantalla negra, cables, BIOS, etc.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                      \u003c/div\u003e\r\n                    \u003c/section\u003e\r\n\r\n                    \u003csection class=\"bitacora-block\"\u003e\r\n                      \u003cdiv class=\"subsection-head\"\u003e\r\n                        \u003cstrong\u003e2. Analisis del fallo\u003c/strong\u003e\r\n                        \u003cp\u003eExplica que causas consideras viables y que accion evitarias de inmediato.\u003c/p\u003e\r\n                      \u003c/div\u003e\r\n                      \u003cdiv class=\"form-grid\"\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003eCausas probables (minimo 3)\u003c/span\u003e\r\n                          \u003ctextarea rows=\"4\" data-store=\"bitacora-causas\" data-track placeholder=\"Ejemplo: ausencia de disco booteable, orden de arranque incorrecto o sistema no instalado.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003eAccion que no realizarias de inmediato y por que\u003c/span\u003e\r\n                          \u003ctextarea rows=\"4\" data-store=\"bitacora-no-hacer\" data-track placeholder=\"Ejemplo: no formatear sin respaldo. Explica la razon.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                      \u003c/div\u003e\r\n                    \u003c/section\u003e\r\n\r\n                    \u003csection class=\"bitacora-block\"\u003e\r\n                      \u003cdiv class=\"subsection-head\"\u003e\r\n                        \u003cstrong\u003e3. Plan de revision y cierre\u003c/strong\u003e\r\n                        \u003cp\u003eOrganiza la secuencia de trabajo, las herramientas digitales y tu conclusion final.\u003c/p\u003e\r\n                      \u003c/div\u003e\r\n                      \u003cdiv class=\"form-grid\"\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003ePlan de revision basico (minimo 5 pasos)\u003c/span\u003e\r\n                          \u003ctextarea rows=\"5\" data-store=\"bitacora-plan\" data-track placeholder=\"Enumera acciones seguras y ordenadas para revisar el caso.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003eHerramientas digitales para documentar y entregar\u003c/span\u003e\r\n                          \u003ctextarea rows=\"5\" data-store=\"bitacora-herramientas\" data-track placeholder=\"Indica al menos 3 herramientas y justifica su uso.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                        \u003clabel\u003e\r\n                          \u003cspan\u003eConclusion breve\u003c/span\u003e\r\n                          \u003ctextarea rows=\"4\" data-store=\"bitacora-conclusion\" data-track placeholder=\"Resume hallazgos, decisiones y cuidados tecnicos.\"\u003e\u003c/textarea\u003e\r\n                        \u003c/label\u003e\r\n                      \u003c/div\u003e\r\n                    \u003c/section\u003e\r\n                  \u003c/div\u003e\r\n\r\n                  \u003cdiv class=\"checklist-card compact-card\" style=\"margin-top:16px;\"\u003e\r\n                    \u003ch3\u003eProducto para entregar\u003c/h3\u003e\r\n                    \u003cp\u003eLa evidencia final debe quedar organizada y completa con los siguientes elementos:\u003c/p\u003e\r\n                    \u003cul class=\"note-list\"\u003e\r\n                      \u003cli\u003eRegistro del caso y contexto observado.\u003c/li\u003e\r\n                      \u003cli\u003eCausas probables del fallo.\u003c/li\u003e\r\n                      \u003cli\u003ePlan de revision por pasos.\u003c/li\u003e\r\n                      \u003cli\u003eHerramientas digitales seleccionadas y su justificacion.\u003c/li\u003e\r\n                      \u003cli\u003eConclusion breve del analisis realizado.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/form\u003e\r\n\r\n                \u003caside class=\"support-column\"\u003e\r\n                  \u003cdiv class=\"checklist-card compact-card\"\u003e\r\n                    \u003ch4\u003eCriterios para una buena respuesta\u003c/h4\u003e\r\n                    \u003cul class=\"mini-list\"\u003e\r\n                      \u003cli\u003eLa descripcion del fallo debe coincidir con las evidencias visuales.\u003c/li\u003e\r\n                      \u003cli\u003eLas causas probables deben ser tecnicamente coherentes con el mensaje de arranque.\u003c/li\u003e\r\n                      \u003cli\u003eEl plan de revision debe ir de lo mas seguro y basico a lo mas especifico.\u003c/li\u003e\r\n                      \u003cli\u003eLa herramienta digital elegida debe apoyar la documentacion y la entrega.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                  \u003c/div\u003e\r\n                  \u003cdiv class=\"support-card\"\u003e\r\n                    \u003cimg src=\"assets/img/producto-entregar.png\" alt=\"Resumen del producto a entregar\"\u003e\r\n                    \u003cp\u003eUsa esta pagina como borrador y luego organiza la entrega final con un archivo formal de bitacora o informe.\u003c/p\u003e\r\n                  \u003c/div\u003e\r\n                  \u003cdiv class=\"support-card\"\u003e\r\n                    \u003cimg src=\"assets/img/socializacion.png\" alt=\"Indicaciones para socializacion\"\u003e\r\n                    \u003cp\u003eDurante la socializacion cada equipo debe exponer una causa probable, un paso del plan de revision y una herramienta digital seleccionada.\u003c/p\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/aside\u003e\r\n              \u003c/div\u003e\r\n              \u003cdiv id=\"guia5311DeadlineControls\" style=\"margin-top:12px\"\u003e\u003c/div\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"contexto\" class=\"section-title\"\u003e3.2 \u0026middot; Contextualizaci\u0026oacute;n e Identificaci\u0026oacute;n de Conocimientos\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eEn esta etapa reconocer\u0026aacute; vocabulario t\u0026eacute;cnico y herramientas digitales que le ayudar\u0026aacute;n a comprender mejor el contexto de soporte e instalaci\u0026oacute;n.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-contexto\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128269;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Contextualizaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003e1 actividad \u0026middot; Duraci\u0026oacute;n aproximada: 1 hora\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.2.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eReconocimiento de conceptos y herramientas\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision diagnostica\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e reforzar el vocabulario t\u0026eacute;cnico (herramientas, protocolos, manuales) mediante dos juegos cortos integrados desde Educaplay. No hay archivo que entregar: el sistema registra el resultado.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g5-2\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eC\u0026oacute;mo navegar entre las dos partes\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g5-2\" data-ihelp-title=\"C\u0026oacute;mo navegar entre las dos partes\"\u003e\n                \u003col\u003e\r\n                      \u003cli\u003eEmpiece con \u003cstrong\u003eParte 1 - Sopa de Letras\u003c/strong\u003e. Cuando termine, cambie a la pesta\u0026ntilde;a \u003cstrong\u003eParte 2 - Relaciona nombre y concepto\u003c/strong\u003e.\u003c/li\u003e\r\n                      \u003cli\u003eSi los juegos no cargan, recargue la p\u0026aacute;gina (F5) o revise su conexi\u0026oacute;n.\u003c/li\u003e\r\n                      \u003cli\u003eSi tiene poca pantalla, use el bot\u0026oacute;n de \"pantalla completa\" del propio iframe.\u003c/li\u003e\r\n                    \u003c/ol\u003e\r\n                    \u003cp\u003eNo requiere botones de Guardar/Exportar. Si necesita evidencia, capture la pantalla cuando complete cada juego.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003cp class=\"intro-text\" style=\"margin-top:8px\"\u003eEsta actividad consta de dos partes para fortalecer el reconocimiento de vocabulario tecnico y la asociacion de herramientas con sus conceptos. Resuelvelas directamente aqui.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"game-tabs\"\u003e\r\n                \u003cbutton class=\"game-tab active\" type=\"button\" onclick=\"switchTab(this,\u0027tab-sopa-guia5\u0027)\"\u003eParte 1 - Sopa de Letras\u003c/button\u003e\r\n                \u003cbutton class=\"game-tab\" type=\"button\" onclick=\"switchTab(this,\u0027tab-relaciona-guia5\u0027)\"\u003eParte 2 - Relaciona nombre y concepto\u003c/button\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"game-panel\" id=\"tab-sopa-guia5\"\u003e\r\n                \u003cdiv class=\"info-box\" style=\"margin-bottom:12px\"\u003e\r\n                  \u003cdiv class=\"label\"\u003eInstrucciones - Sopa de Letras\u003c/div\u003e\r\n                  \u003cul\u003e\r\n                    \u003cli\u003eIdentifica terminos asociados con herramientas, protocolos y manuales tecnicos.\u003c/li\u003e\r\n                    \u003cli\u003eRelaciona el vocabulario encontrado con el contexto de soporte e instalacion.\u003c/li\u003e\r\n                    \u003cli\u003eComenta con el grupo los conceptos que resulten mas utiles para la guia.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv class=\"game-frame-wrap\"\u003e\r\n                  \u003ciframe referrerpolicy=\"strict-origin-when-cross-origin\" allow=\"fullscreen; autoplay; allow-top-navigation-by-user-activation\" allowfullscreen width=\"795\" height=\"690\" frameborder=\"0\" src=\"https://es.educaplay.com/juego/27988460-operar_herramientas_informaticas_y_digitales_de_acuerdo_con_protocolos_y_manuales_tecnicos.html\"\u003e\u003c/iframe\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"game-panel\" id=\"tab-relaciona-guia5\" style=\"display:none\"\u003e\r\n                \u003cdiv class=\"info-box green\" style=\"margin-bottom:12px\"\u003e\r\n                  \u003cdiv class=\"label\"\u003eInstrucciones - Relaciona nombre y concepto\u003c/div\u003e\r\n                  \u003cul\u003e\r\n                    \u003cli\u003eLee cada concepto antes de seleccionar la relacion correspondiente.\u003c/li\u003e\r\n                    \u003cli\u003eUsa lo trabajado en la sopa de letras como apoyo conceptual.\u003c/li\u003e\r\n                    \u003cli\u003eVerifica que cada herramienta quede asociada con su funcion principal.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv class=\"game-frame-wrap\"\u003e\r\n                  \u003ciframe referrerpolicy=\"strict-origin-when-cross-origin\" allow=\"fullscreen; autoplay; allow-top-navigation-by-user-activation\" allowfullscreen width=\"795\" height=\"690\" frameborder=\"0\" src=\"https://es.educaplay.com/juego/27988974-operar_herramientas_informaticas_y_digitales_de_acuerdo_con_protocolos_y_manuales_tecnicos.html\"\u003e\u003c/iframe\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"info-box\" style=\"margin-top:14px\"\u003e\r\n                \u003cdiv class=\"label\"\u003eDatos de la actividad\u003c/div\u003e\r\n                \u003cul\u003e\r\n                  \u003cli\u003eDuracion: 1 hora.\u003c/li\u003e\r\n                  \u003cli\u003eDesarrolla primero la sopa de letras y luego la actividad de relacion.\u003c/li\u003e\r\n                  \u003cli\u003eUsa los conceptos reconocidos como apoyo para las actividades posteriores de la guia.\u003c/li\u003e\r\n                \u003c/ul\u003e\r\n              \u003c/div\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"apropiacion\" class=\"section-title\"\u003e3.3 \u0026middot; Actividades de Apropiaci\u0026oacute;n\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eAqu\u0026iacute; aplicar\u0026aacute; criterios t\u0026eacute;cnicos para clasificar archivos, consultar requerimientos m\u0026iacute;nimos y registrar informaci\u0026oacute;n de forma organizada.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-apropiacion\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128218;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Apropiaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003e1 actividad \u0026middot; Duraci\u0026oacute;n aproximada: 2 horas\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.3.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eClasificacion tecnica de archivos y sistemas\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision tecnica\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e dos sub-actividades en una: (1) clasificar extensiones de archivo con su programa, y (2) consultar e investigar los requerimientos m\u0026iacute;nimos de 3-5 sistemas operativos. Cada sub-actividad exporta su propio Word.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g5-3\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eReglas para las dos tablas\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g5-3\" data-ihelp-title=\"Reglas para las dos tablas\"\u003e\n                \u003cp\u003e\u003cstrong\u003eTabla 1 - Extensiones:\u003c/strong\u003e\u003c/p\u003e\r\n                    \u003cul\u003e\r\n                      \u003cli\u003ePara cada fila escriba el programa principal que abre esa extensi\u0026oacute;n y una descripci\u0026oacute;n corta del tipo de archivo.\u003c/li\u003e\r\n                      \u003cli\u003eUse el desplegable de sugerencias para no repetir nombres.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                    \u003cp\u003e\u003cstrong\u003eTabla 2 - Sistemas operativos:\u003c/strong\u003e\u003c/p\u003e\r\n                    \u003cul\u003e\r\n                      \u003cli\u003eLa columna \u003cem\u003eFuente\u003c/em\u003e debe llevar el sitio oficial donde consult\u0026oacute; (ej. \u003ccode\u003emicrosoft.com\u003c/code\u003e, \u003ccode\u003eubuntu.com\u003c/code\u003e).\u003c/li\u003e\r\n                      \u003cli\u003eNo copie y pegue p\u0026aacute;rrafos: anote solo procesador, RAM y disco m\u0026iacute;nimo.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                    \u003cp\u003eCada tabla tiene su propio bot\u0026oacute;n \u003cem\u003eExportar actividad a Word\u003c/em\u003e. Exporte y entregue las dos antes de cerrar la actividad.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"warning-box\"\u003e\r\n                \u003cstrong\u003eImportante\u003c/strong\u003e\r\n                \u003cp\u003eSolo se permite el uso e instalacion de herramientas licenciadas o de codigo abierto. Registra la fuente consultada para cada sistema operativo en la matriz.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"subsection-head\" style=\"margin-top:16px;\"\u003e\r\n                \u003ch3\u003eActividad 1: Extensiones de archivo\u003c/h3\u003e\r\n                \u003cp\u003eCompleta el programa asociado y la descripcion de cada extension.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n              \u003cdiv class=\"table-scroll\"\u003e\r\n                \u003ctable class=\"data-table\"\u003e\r\n                  \u003cthead\u003e\r\n                    \u003ctr\u003e\r\n                      \u003cth\u003eExtension\u003c/th\u003e\r\n                      \u003cth\u003ePrograma / referencia\u003c/th\u003e\r\n                      \u003cth\u003eDescripcion o tipo de archivo\u003c/th\u003e\r\n                    \u003c/tr\u003e\r\n                  \u003c/thead\u003e\r\n                  \u003ctbody id=\"extensionTable\"\u003e\u003c/tbody\u003e\r\n                \u003c/table\u003e\r\n              \u003c/div\u003e\r\n              \u003cbutton class=\"btn-export-word\" type=\"button\" onclick=\"openGuide5ExportModal(\u0027extensions\u0027)\"\u003e\r\n                📄 Exportar actividad a Word\r\n              \u003c/button\u003e\r\n\r\n              \u003cdatalist id=\"programSuggestions\"\u003e\r\n                \u003coption value=\"Microsoft Word\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Microsoft Excel\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Microsoft Access\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Microsoft Project\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Microsoft PowerPoint\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Microsoft Publisher\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Adobe Acrobat Reader\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"WinRAR\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"VLC Media Player\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Windows\"\u003e\u003c/option\u003e\r\n                \u003coption value=\"Navegador web\"\u003e\u003c/option\u003e\r\n              \u003c/datalist\u003e\r\n\r\n              \u003cdiv class=\"subsection-head\" style=\"margin-top:20px;\"\u003e\r\n                \u003ch3\u003eActividad 2: Requerimientos minimos de sistemas operativos\u003c/h3\u003e\r\n                \u003cp\u003eInvestiga procesador, RAM, espacio en disco y la fuente consultada.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n              \u003cdiv class=\"table-scroll\"\u003e\r\n                \u003ctable class=\"data-table\"\u003e\r\n                  \u003cthead\u003e\r\n                    \u003ctr\u003e\r\n                      \u003cth\u003eSistema operativo\u003c/th\u003e\r\n                      \u003cth\u003eProcesador\u003c/th\u003e\r\n                      \u003cth\u003eRAM\u003c/th\u003e\r\n                      \u003cth\u003eEspacio en disco\u003c/th\u003e\r\n                      \u003cth\u003eFuente\u003c/th\u003e\r\n                    \u003c/tr\u003e\r\n                  \u003c/thead\u003e\r\n                  \u003ctbody id=\"systemTable\"\u003e\u003c/tbody\u003e\r\n                \u003c/table\u003e\r\n              \u003c/div\u003e\r\n              \u003cbutton class=\"btn-export-word\" type=\"button\" onclick=\"openGuide5ExportModal(\u0027systems\u0027)\"\u003e\r\n                📄 Exportar actividad a Word\r\n              \u003c/button\u003e\r\n              \u003cdiv id=\"guia5331DeadlineControls\" style=\"margin-top:12px\"\u003e\u003c/div\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"transferencia\" class=\"section-title\"\u003e3.4 \u0026middot; Actividades de Transferencia del Conocimiento\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eEsta actividad integradora consolida el diagn\u0026oacute;stico, la investigaci\u0026oacute;n y la documentaci\u0026oacute;n t\u0026eacute;cnica en un producto final organizado.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-transferencia\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128640;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Transferencia\u003c/h3\u003e\r\n              \u003cp\u003e1 actividad integradora \u0026middot; Duraci\u0026oacute;n aproximada: 4 horas\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.4.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eGuia de instalacion y evidencia tecnica\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision integradora\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e instalar Linux y Windows en m\u0026aacute;quinas virtuales (VirtualBox) documentando cada paso con capturas. Producto final: informe t\u0026eacute;cnico bajo normas IEEE con el nombre \u003ccode\u003eGuia5_Taller1_NombreAprendiz.doc\u003c/code\u003e.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g5-4\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eVirtualBox y m\u0026aacute;quinas virtuales\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g5-4\" data-ihelp-title=\"VirtualBox y m\u0026aacute;quinas virtuales\"\u003e\n                \u003cp\u003e\u003cstrong\u003e\u0026iquest;Qu\u0026eacute; es?\u003c/strong\u003e Un programa gratuito de Oracle que permite \"crear computadores dentro de su computador\". Esos computadores virtuales (VM) sirven para instalar sistemas operativos sin afectar el equipo real.\u003c/p\u003e\r\n                    \u003cp\u003e\u003cstrong\u003eParticiones de Linux que debe evidenciar:\u003c/strong\u003e\u003c/p\u003e\r\n                    \u003cul\u003e\r\n                      \u003cli\u003e\u003ccode\u003e/\u003c/code\u003e (ra\u0026iacute;z): donde vive el sistema.\u003c/li\u003e\r\n                      \u003cli\u003e\u003ccode\u003e/home\u003c/code\u003e: archivos personales del usuario.\u003c/li\u003e\r\n                      \u003cli\u003e\u003ccode\u003eswap\u003c/code\u003e: memoria de respaldo (similar a \"pagefile\" de Windows).\u003c/li\u003e\r\n                      \u003cli\u003e\u003ccode\u003e/boot\u003c/code\u003e: cargador de arranque.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                    \u003cp\u003e\u003cstrong\u003eCapturas obligatorias:\u003c/strong\u003e configuraci\u0026oacute;n inicial de la VM, particionado, instalaci\u0026oacute;n en progreso, primer inicio del sistema y verificaci\u0026oacute;n (mostrar versi\u0026oacute;n del SO).\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"subsection-head\"\u003e\r\n                \u003ch3\u003eActividad 1: Guia de instalacion de sistemas operativos\u003c/h3\u003e\r\n                \u003cp\u003eElabora una guia de instalacion paso a paso con capturas de pantalla y evidencias claras de cada fase.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"info-box\" style=\"margin-bottom:16px\"\u003e\r\n                \u003cdiv class=\"label\"\u003eIndicaciones esenciales\u003c/div\u003e\r\n                \u003cul class=\"note-list\"\u003e\r\n                  \u003cli\u003eParte A: instala Linux en VirtualBox con la distribucion asignada por tu instructor.\u003c/li\u003e\r\n                  \u003cli\u003eEvidencia la tabla de particiones requerida: \u003ccode\u003e/home\u003c/code\u003e, \u003ccode\u003eswap\u003c/code\u003e, \u003ccode\u003e/boot\u003c/code\u003e y \u003ccode\u003e/\u003c/code\u003e.\u003c/li\u003e\r\n                  \u003cli\u003eParte B: instala Windows en VirtualBox con el sistema operativo designado por tu instructor.\u003c/li\u003e\r\n                  \u003cli\u003eEvidencia el manejo de particiones primaria, logica y extendida, segun corresponda.\u003c/li\u003e\r\n                  \u003cli\u003eEn ambos casos toma capturas de configuracion, particionado, instalacion, primer inicio y verificacion.\u003c/li\u003e\r\n                \u003c/ul\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"transfer-grid\"\u003e\r\n                \u003carticle class=\"transfer-card\"\u003e\r\n                  \u003ch3\u003eParte A: Linux en VirtualBox\u003c/h3\u003e\r\n                  \u003cp\u003eUsa la distribucion asignada por tu instructor e incluye evidencia del particionado \u003ccode\u003e/home\u003c/code\u003e, \u003ccode\u003eswap\u003c/code\u003e, \u003ccode\u003e/boot\u003c/code\u003e y \u003ccode\u003e/\u003c/code\u003e.\u003c/p\u003e\r\n                  \u003cul class=\"note-list\"\u003e\r\n                    \u003cli\u003eConfigure la maquina virtual de acuerdo con la practica asignada.\u003c/li\u003e\r\n                    \u003cli\u003eDocumente el particionado requerido del sistema Linux.\u003c/li\u003e\r\n                    \u003cli\u003eCapture cada fase de la instalacion paso a paso.\u003c/li\u003e\r\n                    \u003cli\u003eVerifique y evidencie el primer inicio del sistema.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                \u003c/article\u003e\r\n\r\n                \u003carticle class=\"transfer-card\"\u003e\r\n                  \u003ch3\u003eParte B: Windows en VirtualBox\u003c/h3\u003e\r\n                  \u003cp\u003eEvidencia el manejo de particiones primaria, logica y extendida segun corresponda para la practica asignada.\u003c/p\u003e\r\n                  \u003cul class=\"note-list\"\u003e\r\n                    \u003cli\u003eConfigure la maquina virtual para la instalacion de Windows.\u003c/li\u003e\r\n                    \u003cli\u003eDocumente el manejo de particiones y almacenamiento.\u003c/li\u003e\r\n                    \u003cli\u003eCapture la instalacion paso a paso.\u003c/li\u003e\r\n                    \u003cli\u003eVerifique el arranque y el funcionamiento del sistema.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                \u003c/article\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"subsection-head\" style=\"margin-top:20px;\"\u003e\r\n                \u003ch3\u003eActividad 2: Desarrollo del taller complementario\u003c/h3\u003e\r\n                \u003cp\u003eRealiza las actividades relacionadas en el documento \u003cstrong\u003eTaller 1_Guia5\u003c/strong\u003e complementarias a la guia de aprendizaje. Al finalizar, adjunta los resultados al documento de evidencia.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"info-box\" style=\"margin-top:16px\"\u003e\r\n                \u003cdiv class=\"label\"\u003eInstalador base para la practica\u003c/div\u003e\r\n                \u003cp\u003eAbre el instalador de VirtualBox antes de iniciar la evidencia tecnica y usalo como apoyo para crear las maquinas virtuales de Linux y Windows.\u003c/p\u003e\r\n                \u003cdiv class=\"drive-action-group\"\u003e\r\n                  \u003ca class=\"btn-drive\" href=\"https://drive.google.com/drive/folders/19AY6LsSHM--2VVXp4_Bzzjz2SVyAiSMc?usp=sharing\" target=\"_blank\" rel=\"noopener noreferrer\"\u003e💻 Abrir instalador de VirtualBox en Drive ↗\u003c/a\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"subsection-head\" style=\"margin-top:20px;\"\u003e\r\n                \u003ch3\u003eInforme tecnico (Documento bajo normas IEEE)\u003c/h3\u003e\r\n                \u003cp\u003eElabora un informe tecnico bajo normas IEEE que incluya todo el desarrollo del taller, es decir, las Actividades 1 y 2, con sus respectivas evidencias: capturas, tablas y respuestas.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"panel-grid panel-grid-single\" style=\"margin-top:16px;\"\u003e\r\n                \u003carticle class=\"checklist-card\"\u003e\r\n                  \u003ch3\u003eInforme tecnico bajo normas IEEE\u003c/h3\u003e\r\n                  \u003cp\u003eEl informe final debe integrar el desarrollo de las Actividades 1 y 2 con sus respectivas evidencias: capturas, tablas, respuestas y conclusiones.\u003c/p\u003e\r\n                  \u003ch4\u003eAntes de enviar\u003c/h4\u003e\r\n                  \u003cul class=\"note-list\"\u003e\r\n                    \u003cli\u003eVerifica que respondiste todos los puntos solicitados.\u003c/li\u003e\r\n                    \u003cli\u003eIncluye capturas de pantalla claras y bien organizadas.\u003c/li\u003e\r\n                    \u003cli\u003eCuida la ortografia y la redaccion tecnica del documento.\u003c/li\u003e\r\n                    \u003cli\u003eRevisa que el formato IEEE este completo.\u003c/li\u003e\r\n                    \u003cli\u003eUsa el nombre de archivo \u003ccode\u003eGuia5_Taller1_NombreAprendiz.doc\u003c/code\u003e.\u003c/li\u003e\r\n                    \u003cli\u003eEntrega el archivo final en el enlace dispuesto por tu instructor.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                  \u003cdiv class=\"info-box\" style=\"margin-top:16px\"\u003e\r\n                    \u003cdiv class=\"label\"\u003eNota importante\u003c/div\u003e\r\n                    \u003cp\u003eLa estructura minima del documento debe incluir los siguientes apartados:\u003c/p\u003e\r\n                    \u003cul class=\"note-list\"\u003e\r\n                      \u003cli\u003eAbstract (resumen en ingles).\u003c/li\u003e\r\n                      \u003cli\u003eKeywords (palabras clave).\u003c/li\u003e\r\n                      \u003cli\u003eIntroduccion: explica de que trata el documento.\u003c/li\u003e\r\n                      \u003cli\u003eContenido: desarrollo de las actividades planteadas.\u003c/li\u003e\r\n                      \u003cli\u003eConclusiones: explica que aprendiste en la practica.\u003c/li\u003e\r\n                      \u003cli\u003eBibliografia presentada bajo normas IEEE.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/article\u003e\r\n\r\n              \u003c/div\u003e\r\n              \u003cdiv id=\"guia5341DeadlineControls\" style=\"margin-top:12px\"\u003e\u003c/div\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"evidencias\" class=\"section-title\"\u003ePlanteamiento de Evidencias de Aprendizaje\u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-evaluacion\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128202;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eEvidencias y Criterios de Evaluaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003eResumen de lo que debe entregar y c\u0026oacute;mo ser\u0026aacute; evaluado\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"table-scroll\"\u003e\r\n            \u003ctable class=\"data-table\"\u003e\r\n              \u003cthead\u003e\r\n                \u003ctr\u003e\r\n                  \u003cth\u003eFase del proyecto\u003c/th\u003e\r\n                  \u003cth\u003eActividad del proyecto\u003c/th\u003e\r\n                  \u003cth\u003eActividad de aprendizaje\u003c/th\u003e\r\n                  \u003cth\u003eEvidencias\u003c/th\u003e\r\n                  \u003cth\u003eCriterios de evaluacion\u003c/th\u003e\r\n                  \u003cth\u003eTecnicas e instrumentos\u003c/th\u003e\r\n                \u003c/tr\u003e\r\n              \u003c/thead\u003e\r\n              \u003ctbody id=\"evidenceTable\"\u003e\u003c/tbody\u003e\r\n            \u003c/table\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"glosario\" class=\"section-title\"\u003eGlosario de T\u0026eacute;rminos\u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-glosario\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128214;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eGlosario de T\u0026eacute;rminos\u003c/h3\u003e\r\n              \u003cp\u003eDefiniciones clave para comprender la gu\u0026iacute;a y sus actividades\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003clabel class=\"search-box\"\u003e\r\n            \u003cspan\u003eBuscar termino\u003c/span\u003e\r\n            \u003cinput type=\"search\" id=\"glossarySearch\" placeholder=\"Ejemplo: BIOS, backup, particion, hipervisor\"\u003e\r\n          \u003c/label\u003e\r\n          \u003cdiv class=\"glossary-grid\" id=\"glossaryGrid\"\u003e\u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"referencias\" class=\"section-title\"\u003eReferentes Bibliogr\u0026aacute;ficos\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#ede7f6\"\u003e\u0026#128279;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eReferencias Bibliogr\u0026aacute;ficas\u003c/h3\u003e\r\n              \u003cp\u003eFuentes consultadas para orientar esta gu\u0026iacute;a y sus actividades\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003col class=\"reference-list\"\u003e\r\n            \u003cli\u003eServicio Nacional de Aprendizaje (SENA). Guia de aprendizaje - Formato GFPI-F-135.\u003c/li\u003e\r\n            \u003cli\u003eOracle. Oracle VM VirtualBox User Manual.\u003c/li\u003e\r\n            \u003cli\u003eVMware. Workstation / Player Documentation.\u003c/li\u003e\r\n            \u003cli\u003eMicrosoft. Documentacion oficial de instalacion y soporte de Windows 10 y Windows 11.\u003c/li\u003e\r\n            \u003cli\u003eCanonical Ltd. Ubuntu Documentation.\u003c/li\u003e\r\n            \u003cli\u003eLinux Foundation. Filesystem Hierarchy Standard.\u003c/li\u003e\r\n            \u003cli\u003eIEEE. IEEE Editorial Style Manual / IEEE Style Guide.\u003c/li\u003e\r\n            \u003cli\u003eNIST. Computer Security Resource Center.\u003c/li\u003e\r\n            \u003cli\u003eGoogle. Centro de ayuda de Google Drive.\u003c/li\u003e\r\n            \u003cli\u003eMicrosoft. Centro de ayuda de Microsoft Teams y SharePoint.\u003c/li\u003e\r\n          \u003c/ol\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"material-apoyo\" class=\"section-title\"\u003eMaterial de Apoyo\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#e8f0fe\"\u003e\u0026#128194;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eMaterial de Apoyo y Recursos\u003c/h3\u003e\r\n              \u003cp\u003eRecursos visuales y orientaciones para acompa\u0026ntilde;ar el desarrollo de la gu\u0026iacute;a\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"info-box\"\u003e\r\n            \u003cdiv class=\"label\"\u003eRuta local del material\u003c/div\u003e\r\n            \u003cp\u003e\r\n              Este material se abre desde la ruta\r\n              \u003ccode class=\"support-path\"\u003eassets/materiales/guia5\u003c/code\u003e.\r\n            \u003c/p\u003e\r\n          \u003c/div\u003e\r\n\r\n          \u003cdiv class=\"material-heading\"\u003ePlantillas de trabajo\u003c/div\u003e\r\n          \u003cdiv class=\"resource-grid\" id=\"supportTemplatesGrid\"\u003e\u003c/div\u003e\r\n\r\n          \u003cdiv class=\"material-heading\"\u003eDocumentos y guias de consulta\u003c/div\u003e\r\n          \u003cdiv class=\"resource-grid\" id=\"supportDocsGrid\"\u003e\u003c/div\u003e\r\n\r\n          \u003cdiv class=\"material-heading\"\u003eHerramientas y software\u003c/div\u003e\r\n          \u003cdiv class=\"resource-grid\" id=\"supportToolsGrid\"\u003e\u003c/div\u003e\r\n\r\n          \u003cdiv class=\"panel-grid\" style=\"margin-top:16px;\"\u003e\r\n            \u003cdiv class=\"support-card\"\u003e\r\n              \u003cimg src=\"assets/img/no-bootable-device.jpeg\" alt=\"Error no bootable device\"\u003e\r\n              \u003cp\u003eReferencia visual 1: mensaje clasico cuando el equipo no encuentra un medio valido de arranque.\u003c/p\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"support-card\"\u003e\r\n              \u003cimg src=\"assets/img/sopa-letras.png\" alt=\"Sopa de letras\"\u003e\r\n              \u003cp\u003eReferencia visual 2: material de apoyo para la actividad de contextualizacion y vocabulario tecnico.\u003c/p\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"notes-card\"\u003e\r\n              \u003ch3\u003eSugerencias de uso\u003c/h3\u003e\r\n              \u003cul class=\"note-list\"\u003e\r\n                \u003cli\u003eUsa la bitacora y el taller como base para estructurar tus entregas.\u003c/li\u003e\r\n                \u003cli\u003eConsulta VirtualBox y Linux Boot Process antes de la practica de instalacion.\u003c/li\u003e\r\n                \u003cli\u003eApoya el informe final con los documentos de normas IEEE y ciberseguridad.\u003c/li\u003e\r\n                \u003cli\u003eGuarda evidencias con nombres claros dentro de tu portafolio de aprendizaje.\u003c/li\u003e\r\n              \u003c/ul\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n    \u003c/div\u003e\r\n  \u003c/main\u003e\r\n\u003c/div\u003e\r\n\r\n\u003cdiv class=\"modal-overlay\" id=\"guide5-export-modal\" onclick=\"if(event.target===this)closeGuide5ExportModal()\"\u003e\r\n  \u003cdiv class=\"modal-box\"\u003e\r\n    \u003ch3 id=\"guide5-export-title\"\u003e📄 Exportar actividad a Word\u003c/h3\u003e\r\n    \u003cp id=\"guide5-export-description\"\u003eIngresa tu nombre completo para guardar el documento.\u003c/p\u003e\r\n\r\n    \u003cdiv class=\"modal-ficha-warn\" id=\"guide5-export-warn\" style=\"display:none\"\u003e\r\n      ⚠️ \u003cstrong\u003eNo has seleccionado tu ficha.\u003c/strong\u003e\u003cbr\u003e\r\n      Regresa a \u003ca href=\"index.html\"\u003ela página de inicio\u003c/a\u003e y elige tu institución y grupo antes de exportar.\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"modal-ficha-ok\" id=\"guide5-export-ok\" style=\"display:none\"\u003e\r\n      \u003cdiv class=\"mf-label\"\u003e📎 El archivo se guardará como:\u003c/div\u003e\r\n      \u003cdiv class=\"mf-file\" id=\"guide5-export-filename\"\u003eNombre_Ficha.doc\u003c/div\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cinput\r\n      id=\"guide5-export-name\"\r\n      type=\"text\"\r\n      placeholder=\"Nombre y apellidos del aprendiz\"\r\n      maxlength=\"80\"\r\n      oninput=\"updateGuide5ExportFilenamePreview()\"\r\n      onkeydown=\"if(event.key===\u0027Enter\u0027)doGuide5ExportWord()\"\r\n    \u003e\r\n    \u003cdiv class=\"modal-error-msg\" id=\"guide5-export-error\"\u003ePor favor ingresa tu nombre antes de continuar.\u003c/div\u003e\r\n\r\n    \u003cdiv class=\"modal-actions\"\u003e\r\n      \u003cbutton class=\"modal-btn-cancel\" type=\"button\" onclick=\"closeGuide5ExportModal()\"\u003eCancelar\u003c/button\u003e\r\n      \u003cbutton class=\"modal-btn-ok\" type=\"button\" id=\"guide5-export-ok-btn\" onclick=\"doGuide5ExportWord()\"\u003e⬇ Descargar Word\u003c/button\u003e\r\n    \u003c/div\u003e\r\n  \u003c/div\u003e\r\n\u003c/div\u003e\r\n\r\n\u003cscript\u003e\r\n(function () {\r\n  function buildGuideRouteHref(fileName) {\r\n    return \"guia.html?g=\" + encodeURIComponent(fileName);\r\n  }\r\n\r\n  var grupo = String((document.body \u0026\u0026 document.body.dataset \u0026\u0026 document.body.dataset.defaultGrupo) || \"11A\").toUpperCase();\r\n  var config = {\r\n    \"11A\": {\r\n      currentFile: \"grupo-11a-guia-05-herramientas-informaticas-digitales.html\",\r\n      currentLabel: \"Operar herramientas informaticas y digitales | 11A\",\r\n      campus: \"Santa Barbara | 11A\"\r\n    },\r\n    \"11B\": {\r\n      currentFile: \"grupo-11b-guia-05-herramientas-informaticas-digitales.html\",\r\n      currentLabel: \"Operar herramientas informaticas y digitales | 11B\",\r\n      campus: \"Santa Barbara | 11B\"\r\n    }\r\n  }[grupo] || null;\r\n\r\n  if (!config) {\r\n    return;\r\n  }\r\n\r\n  var currentGuideNavLink = document.getElementById(\"currentGuideNavLink\");\r\n  var currentGuideNavLabel = document.getElementById(\"currentGuideNavLabel\");\r\n  var topbarCampus = document.getElementById(\"topbarCampus\");\r\n\r\n  if (currentGuideNavLink) {\r\n    currentGuideNavLink.href = buildGuideRouteHref(config.currentFile);\r\n    currentGuideNavLink.dataset.currentFile = config.currentFile;\r\n  }\r\n  if (currentGuideNavLabel) {\r\n    currentGuideNavLabel.textContent = config.currentLabel;\r\n  }\r\n  if (topbarCampus) {\r\n    topbarCampus.textContent = config.campus;\r\n  }\r\n})();\r\n\u003c/script\u003e\r\n\u003c!-- INTERACTIVE_HELP_INLINE_START --\u003e\r\n\u003cstyle data-ihelp-inline\u003e\r\n/* css/interactive_help.css\n *\n * Componente \"Material de apoyo interactivo\" — patron usado en la guia de\n * Redes RAP01 (boton verde + panel lateral deslizante con contenido rico).\n *\n * Reusable en cualquier guia. Coexiste con el sistema preexistente\n * #teoria-panel/abrirTeoriaPanel() de la guia de Redes (usa IDs distintos).\n *\n * Estructura HTML esperada:\n *\n *   \u003cdiv class=\"ihelp-trigger\"\u003e\n *     \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-XYZ\"\u003e\n *       \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e📚\u003c/span\u003e\n *       \u003cspan class=\"ihelp-btn__text\"\u003e\n *         \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n *         \u003cspan class=\"ihelp-btn__title\"\u003eTitulo del tema\u003c/span\u003e\n *       \u003c/span\u003e\n *       \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e→\u003c/span\u003e\n *     \u003c/button\u003e\n *     \u003ctemplate id=\"ihelp-XYZ\" data-ihelp-title=\"Titulo\"\u003e\n *       ...HTML enriquecido para el panel...\n *     \u003c/template\u003e\n *   \u003c/div\u003e\n *\n * El panel y el backdrop se inyectan una sola vez por la JS.\n */\n\n/* --- Boton trigger --------------------------------------------------------- */\n.ihelp-trigger {\n  margin: 14px 0 16px;\n}\n\n.ihelp-trigger + .ihelp-trigger {\n  margin-top: 8px;\n}\n\n.ihelp-btn {\n  display: inline-flex;\n  align-items: center;\n  gap: 10px;\n  min-height: 44px;\n  padding: 12px 20px;\n  border: 0;\n  border-radius: 12px;\n  background: linear-gradient(135deg, #007934 0%, #0a5c31 100%);\n  color: #fff;\n  font: 700 0.9rem/1.2 inherit;\n  text-align: left;\n  cursor: pointer;\n  box-shadow: 0 6px 18px rgba(7, 26, 18, 0.18);\n  transition: transform 0.2s ease, box-shadow 0.2s ease, filter 0.2s ease;\n  font-family: inherit;\n  max-width: 100%;\n}\n\n.ihelp-btn:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 10px 28px rgba(7, 26, 18, 0.25);\n}\n\n.ihelp-btn:focus-visible {\n  outline: 2px solid #f5b700;\n  outline-offset: 3px;\n}\n\n.ihelp-btn:active {\n  transform: translateY(0);\n  filter: brightness(0.95);\n}\n\n.ihelp-btn__icon {\n  font-size: 1.3rem;\n  flex-shrink: 0;\n  line-height: 1;\n}\n\n.ihelp-btn__text {\n  display: flex;\n  flex-direction: column;\n  align-items: flex-start;\n  gap: 2px;\n  flex: 1 1 auto;\n  min-width: 0;\n}\n\n.ihelp-btn__kicker {\n  display: block;\n  font-size: 0.72rem;\n  font-weight: 600;\n  opacity: 0.85;\n  letter-spacing: 0.05em;\n  text-transform: uppercase;\n}\n\n.ihelp-btn__title {\n  display: block;\n  font-size: 0.92rem;\n  font-weight: 700;\n  line-height: 1.25;\n}\n\n.ihelp-btn__arrow {\n  margin-left: 6px;\n  font-size: 1.1rem;\n  opacity: 0.85;\n  flex-shrink: 0;\n  transition: transform 0.2s ease;\n}\n\n.ihelp-btn:hover .ihelp-btn__arrow {\n  transform: translateX(2px);\n}\n\n/* --- Panel lateral --------------------------------------------------------- */\n.ihelp-panel {\n  position: fixed;\n  top: 0;\n  right: 0;\n  width: min(500px, 100vw);\n  height: 100dvh;\n  background: #f8fafc;\n  box-shadow: -4px 0 32px rgba(0, 0, 0, 0.22);\n  z-index: 9999;\n  transform: translateX(110%);\n  transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1);\n  display: flex;\n  flex-direction: column;\n  font-family: inherit;\n}\n\n.ihelp-panel[data-open=\"true\"] {\n  transform: translateX(0);\n}\n\n.ihelp-panel__header {\n  background: linear-gradient(135deg, #007934, #0a5c31);\n  color: #fff;\n  padding: 16px 20px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  flex-shrink: 0;\n  gap: 12px;\n}\n\n.ihelp-panel__title {\n  font-weight: 700;\n  font-size: 1rem;\n  line-height: 1.3;\n  margin: 0;\n  flex: 1 1 auto;\n}\n\n.ihelp-panel__close {\n  background: rgba(255, 255, 255, 0.2);\n  border: none;\n  color: #fff;\n  width: 32px;\n  height: 32px;\n  border-radius: 50%;\n  font-size: 1.1rem;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-shrink: 0;\n  transition: background 0.2s ease;\n  font-family: inherit;\n}\n\n.ihelp-panel__close:hover,\n.ihelp-panel__close:focus-visible {\n  background: rgba(255, 255, 255, 0.35);\n  outline: none;\n}\n\n.ihelp-panel__body {\n  flex: 1;\n  overflow-y: auto;\n  padding: 20px 18px;\n  color: #1e2f24;\n  font-size: 0.93rem;\n  line-height: 1.55;\n}\n\n.ihelp-panel__body p {\n  margin: 0 0 10px;\n}\n\n.ihelp-panel__body ul,\n.ihelp-panel__body ol {\n  margin: 6px 0 12px;\n  padding-left: 22px;\n}\n\n.ihelp-panel__body li + li {\n  margin-top: 4px;\n}\n\n.ihelp-panel__body h3,\n.ihelp-panel__body h4 {\n  margin: 14px 0 8px;\n  color: #102117;\n  font-weight: 700;\n  line-height: 1.25;\n}\n\n.ihelp-panel__body h3 {\n  font-size: 1.05rem;\n}\n\n.ihelp-panel__body h4 {\n  font-size: 0.95rem;\n}\n\n.ihelp-panel__body strong {\n  color: #102117;\n}\n\n.ihelp-panel__body code {\n  background: #e8f5e9;\n  color: #1b5e20;\n  padding: 1px 6px;\n  border-radius: 4px;\n  font-family: ui-monospace, \"SFMono-Regular\", Menlo, Consolas, monospace;\n  font-size: 0.88em;\n}\n\n.ihelp-panel__example {\n  margin: 10px 0;\n  padding: 10px 12px;\n  background: #fff9e6;\n  border-left: 3px solid #f5b700;\n  border-radius: 6px;\n  font-size: 0.88rem;\n  color: #6e5300;\n}\n\n.ihelp-panel__example::before {\n  content: \"Ejemplo:\";\n  display: inline-block;\n  margin-right: 6px;\n  font-weight: 700;\n  font-size: 0.74rem;\n  text-transform: uppercase;\n  letter-spacing: 0.04em;\n  color: #8b6a00;\n}\n\n.ihelp-panel__card {\n  background: #fff;\n  border: 1px solid #d6e2da;\n  border-radius: 10px;\n  padding: 12px 14px;\n  margin: 10px 0;\n  box-shadow: 0 1px 2px rgba(7, 26, 18, 0.05);\n}\n\n.ihelp-panel__tip {\n  background: #e6f7ed;\n  border-left: 3px solid #007934;\n  padding: 10px 12px;\n  border-radius: 6px;\n  margin: 10px 0;\n  color: #07391e;\n  font-size: 0.88rem;\n}\n\n.ihelp-panel__warn {\n  background: #fff5d6;\n  border-left: 3px solid #f5b700;\n  padding: 10px 12px;\n  border-radius: 6px;\n  margin: 10px 0;\n  color: #6e5300;\n  font-size: 0.88rem;\n}\n\n/* --- Backdrop -------------------------------------------------------------- */\n.ihelp-backdrop {\n  position: fixed;\n  inset: 0;\n  background: rgba(0, 0, 0, 0.4);\n  z-index: 9998;\n  opacity: 0;\n  pointer-events: none;\n  transition: opacity 0.35s ease;\n}\n\n.ihelp-backdrop[data-open=\"true\"] {\n  opacity: 1;\n  pointer-events: auto;\n}\n\n/* --- Reduced motion -------------------------------------------------------- */\n@media (prefers-reduced-motion: reduce) {\n  .ihelp-panel,\n  .ihelp-backdrop,\n  .ihelp-btn,\n  .ihelp-btn__arrow {\n    transition: none !important;\n  }\n}\n\n/* --- Pantallas pequeñas ---------------------------------------------------- */\n@media (max-width: 480px) {\n  .ihelp-btn {\n    width: 100%;\n    padding: 11px 16px;\n  }\n  .ihelp-btn__title {\n    font-size: 0.88rem;\n  }\n}\n\r\n\u003c/style\u003e\r\n\u003cscript data-ihelp-inline\u003e\r\n/* js/interactive_help.js\n *\n * Componente \"Material de apoyo interactivo\" — boton verde que abre un panel\n * lateral con contenido rico. Mismo patron visual que el sistema preexistente\n * `abrirTeoriaPanel()` de la guia de Redes, pero generico y reusable en\n * cualquier guia.\n *\n * - Usa IDs distintos a los de la guia de Redes (ihelp-panel / ihelp-backdrop)\n *   para coexistir sin colisionar.\n * - Inyecta el panel y el backdrop una sola vez en document.body.\n * - Event delegation sobre document, asi funciona aun cuando los botones se\n *   inyectan dinamicamente desde un partial.\n * - Cada boton lleva data-ihelp-target=\"ID\" apuntando a un \u003ctemplate id=\"ID\"\n *   data-ihelp-title=\"...\"\u003e. La JS extrae el title y el innerHTML del\n *   template y los muestra en el panel.\n * - Atajos: Escape cierra. Click en backdrop cierra.\n */\n(function () {\n  \"use strict\";\n\n  if (typeof window === \"undefined\" || typeof document === \"undefined\") {\n    return;\n  }\n\n  if (window.__INTERACTIVE_HELP_LOADED__) {\n    return;\n  }\n  window.__INTERACTIVE_HELP_LOADED__ = true;\n\n  var panelEl = null;\n  var backdropEl = null;\n  var titleEl = null;\n  var bodyEl = null;\n  var lastTrigger = null;\n\n  function ensurePanel() {\n    if (panelEl \u0026\u0026 document.body.contains(panelEl)) {\n      return;\n    }\n\n    panelEl = document.createElement(\"div\");\n    panelEl.className = \"ihelp-panel\";\n    panelEl.setAttribute(\"role\", \"dialog\");\n    panelEl.setAttribute(\"aria-modal\", \"true\");\n    panelEl.setAttribute(\"aria-labelledby\", \"ihelp-panel-title\");\n    panelEl.setAttribute(\"data-open\", \"false\");\n    panelEl.setAttribute(\"aria-hidden\", \"true\");\n\n    var header = document.createElement(\"div\");\n    header.className = \"ihelp-panel__header\";\n\n    titleEl = document.createElement(\"h2\");\n    titleEl.className = \"ihelp-panel__title\";\n    titleEl.id = \"ihelp-panel-title\";\n    header.appendChild(titleEl);\n\n    var closeBtn = document.createElement(\"button\");\n    closeBtn.type = \"button\";\n    closeBtn.className = \"ihelp-panel__close\";\n    closeBtn.setAttribute(\"aria-label\", \"Cerrar material de apoyo\");\n    closeBtn.textContent = \"✕\";\n    closeBtn.addEventListener(\"click\", closePanel);\n    header.appendChild(closeBtn);\n\n    bodyEl = document.createElement(\"div\");\n    bodyEl.className = \"ihelp-panel__body\";\n\n    panelEl.appendChild(header);\n    panelEl.appendChild(bodyEl);\n\n    backdropEl = document.createElement(\"div\");\n    backdropEl.className = \"ihelp-backdrop\";\n    backdropEl.setAttribute(\"data-open\", \"false\");\n    backdropEl.addEventListener(\"click\", closePanel);\n\n    document.body.appendChild(backdropEl);\n    document.body.appendChild(panelEl);\n  }\n\n  function openPanel(title, html, triggerEl) {\n    ensurePanel();\n    titleEl.textContent = title || \"\";\n    bodyEl.innerHTML = html || \"\";\n    bodyEl.scrollTop = 0;\n    panelEl.setAttribute(\"data-open\", \"true\");\n    panelEl.setAttribute(\"aria-hidden\", \"false\");\n    backdropEl.setAttribute(\"data-open\", \"true\");\n    document.body.style.overflow = \"hidden\";\n    lastTrigger = triggerEl || null;\n    // Move focus to close button for keyboard users\n    try {\n      var close = panelEl.querySelector(\".ihelp-panel__close\");\n      if (close) {\n        close.focus({ preventScroll: true });\n      }\n    } catch (e) {\n      /* noop */\n    }\n  }\n\n  function closePanel() {\n    if (!panelEl) return;\n    panelEl.setAttribute(\"data-open\", \"false\");\n    panelEl.setAttribute(\"aria-hidden\", \"true\");\n    if (backdropEl) backdropEl.setAttribute(\"data-open\", \"false\");\n    document.body.style.overflow = \"\";\n    // Restore focus to the trigger that opened the panel\n    if (lastTrigger \u0026\u0026 typeof lastTrigger.focus === \"function\") {\n      try { lastTrigger.focus({ preventScroll: true }); } catch (e) { /* noop */ }\n    }\n    lastTrigger = null;\n  }\n\n  function resolveContent(triggerBtn) {\n    var targetId = triggerBtn.getAttribute(\"data-ihelp-target\");\n    if (!targetId) return null;\n    var tpl = document.getElementById(targetId);\n    if (!tpl) return null;\n    var title =\n      tpl.getAttribute(\"data-ihelp-title\") ||\n      (triggerBtn.querySelector(\".ihelp-btn__title\") \u0026\u0026\n        triggerBtn.querySelector(\".ihelp-btn__title\").textContent.trim()) ||\n      \"Material de apoyo\";\n\n    // \u003ctemplate\u003e exposes content via .innerHTML even if .content is empty\n    var html = \"\";\n    if (tpl.tagName \u0026\u0026 tpl.tagName.toUpperCase() === \"TEMPLATE\" \u0026\u0026 tpl.innerHTML) {\n      html = tpl.innerHTML;\n    } else if (tpl.tagName \u0026\u0026 tpl.tagName.toUpperCase() === \"SCRIPT\") {\n      html = tpl.textContent || \"\";\n    } else {\n      html = tpl.innerHTML || \"\";\n    }\n    return { title: title, html: html };\n  }\n\n  function onDocumentClick(event) {\n    var trigger = event.target \u0026\u0026 event.target.closest\n      ? event.target.closest(\".ihelp-btn[data-ihelp-target]\")\n      : null;\n    if (!trigger) return;\n    var content = resolveContent(trigger);\n    if (!content) return;\n    event.preventDefault();\n    openPanel(content.title, content.html, trigger);\n  }\n\n  function onDocumentKeydown(event) {\n    if (event.key === \"Escape\" || event.key === \"Esc\") {\n      if (panelEl \u0026\u0026 panelEl.getAttribute(\"data-open\") === \"true\") {\n        event.preventDefault();\n        closePanel();\n      }\n    }\n  }\n\n  document.addEventListener(\"click\", onDocumentClick);\n  document.addEventListener(\"keydown\", onDocumentKeydown);\n\n  if (document.readyState === \"loading\") {\n    document.addEventListener(\"DOMContentLoaded\", ensurePanel, { once: true });\n  } else {\n    ensurePanel();\n  }\n\n  window.InteractiveHelp = {\n    open: openPanel,\n    close: closePanel,\n    ensurePanel: ensurePanel,\n  };\n})();\n\r\n\u003c/script\u003e\r\n\u003c!-- INTERACTIVE_HELP_INLINE_END --\u003e\r\n";
